// Roboto Latin (Regular + Bold) — Apache 2.0, Google Fonts
// TTF (sfnt) subset: Latin + Latin Extended (~34KB each)
// WOFF aus @fontsource lokal zu TTF konvertiert — kein pako/zlib auf Vercel nötig
// Inlined als base64 für zuverlässiges Vercel-Bundling (kein fs-Zugriff zur Laufzeit)

const ROBOTO_REGULAR_B64 = "";
const ROBOTO_BOLD_B64    = "";

export const robotoRegular: Uint8Array = Buffer.from(ROBOTO_REGULAR_B64, "base64");
export const robotoBold: Uint8Array    = Buffer.from(ROBOTO_BOLD_B64, "base64");